import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <nav style={styles.nav}>
      <Link to="/" style={styles.brand}>📅 AppointEase</Link>
      <div style={styles.links}>
        {!user ? (
          <>
            <Link to="/login" style={styles.link}>Login</Link>
            <Link to="/register" style={styles.link}>Register</Link>
          </>
        ) : (
          <>
            <span style={styles.welcome}>Hi, {user.name} ({user.role})</span>
            {user.role === 'customer' && (
              <Link to="/my-appointments" style={styles.link}>My Appointments</Link>
            )}
            {user.role === 'provider' && (
              <Link to="/dashboard" style={styles.link}>Dashboard</Link>
            )}
            <button onClick={handleLogout} style={styles.btn}>Logout</button>
          </>
        )}
      </div>
    </nav>
  );
}

const styles = {
  nav: {
    display: 'flex', justifyContent: 'space-between', alignItems: 'center',
    padding: '14px 30px', background: '#1a73e8', color: '#fff'
  },
  brand: { color: '#fff', fontSize: '20px', fontWeight: 'bold', textDecoration: 'none' },
  links: { display: 'flex', alignItems: 'center', gap: '16px' },
  link: { color: '#fff', textDecoration: 'none', fontSize: '15px' },
  welcome: { fontSize: '14px', opacity: 0.9 },
  btn: {
    background: '#fff', color: '#1a73e8', border: 'none',
    padding: '6px 14px', borderRadius: '6px', cursor: 'pointer', fontWeight: 'bold'
  }
};
